def mode(nums):
    if not nums:
        return None
    counter = {}
    for n in nums:
        if n in counter:
            counter[n] += 1
        else:
            counter[n] = 1
    most_common, _ = max(counter.items(), key=lambda item: item[1])
    min_mode = min(filter(lambda x: x == most_common, counter.keys()))
    return min_mode
